SELECT [Transfer Shipment Line].[Document No_], [Transfer Shipment Line].[Item Type], [Transfer Shipment Line].[Item No_], [Transfer Shipment Line].[Constant Variable Code], [Transfer Shipment Line].[Season Code], [Transfer Shipment Line].[Shipment Date], Sum(Val([NO_ OF PAIRS])) AS QTY, [Transfer Shipment Line].[Transfer Order No_], [Transfer Shipment Line].Description, [Transfer Shipment Header].Note, [Transfer Shipment Header].Typification
FROM 000_dam_AnalisiArriviMerceN_step0TransferShipment_ReceiptFilter INNER JOIN ([Transfer Shipment Line] INNER JOIN [Transfer Shipment Header] ON [Transfer Shipment Line].[Document No_] = [Transfer Shipment Header].No_) ON [000_dam_AnalisiArriviMerceN_step0TransferShipment_ReceiptFilter].[Transfer Order No_] = [Transfer Shipment Line].[Transfer Order No_]
GROUP BY [Transfer Shipment Line].[Document No_], [Transfer Shipment Line].[Item Type], [Transfer Shipment Line].[Item No_], [Transfer Shipment Line].[Constant Variable Code], [Transfer Shipment Line].[Season Code], [Transfer Shipment Line].[Shipment Date], [Transfer Shipment Line].[Transfer Order No_], [Transfer Shipment Line].Description, [Transfer Shipment Header].Note, [Transfer Shipment Header].Typification
HAVING ((([Transfer Shipment Line].[Item Type])=19 Or ([Transfer Shipment Line].[Item Type])=20) AND (([Transfer Shipment Line].[Season Code])=[CODICE STAGIONE]));

